console.log('[app] carregou');

// Utilitário: falhe cedo com mensagem clara
function assertEl(selector) {
  const el = document.querySelector(selector);
  if (el === null) {
    console.error(`[app] elemento não encontrado: ${selector}`);
    return null;
  }
  return el;
}

const elValor = assertEl('#valor');
const elStatus = assertEl('#status');
const btnMenos = assertEl('#menos');
const btnMais = assertEl('#mais');
const btnZerar = assertEl('#zerar');
const btnMais5 = assertEl('#mais5');

// Se algo essencial estiver faltando, não continue.
if (!elValor || !elStatus || !btnMenos || !btnMais || !btnZerar || !btnMais5) {
  console.warn('[app] inicialização abortada por falta de elementos.');
} else {
  let valor = 0;

  function render() {
    elValor.textContent = String(valor);
    elStatus.textContent = (valor % 2 === 0) ? 'Par' : 'Ímpar';
  }

  function setValor(novoValor) {
    if (typeof novoValor !== 'number') {
      console.error('[app] setValor recebeu tipo inválido:', typeof novoValor);
      return;
    }

    if (Number.isNaN(novoValor)) {
      console.error('[app] setValor recebeu NaN');
      return;
    }

    if (novoValor < 0) {
      console.log('[app] limite: não pode ficar menor que 0');
      valor = 0;
    } else {
      valor = novoValor;
    }

    if (valor === 10) {
      console.log('[app] Chegou em 10!');
    }

    render();
  }

  btnMenos.addEventListener('click', () => setValor(valor - 1));
  btnMais.addEventListener('click', () => setValor(valor + 1));
  btnMais5.addEventListener('click', () => setValor(valor + 5));
  btnZerar.addEventListener('click', () => setValor(0));

  render();
}
